description = "How to handle a plugin's declared system dependencies before installing a tool."
docs = """
Controls what mise does when a plugin declares system prerequisites (build tools,
libraries, ...) via `PLUGIN.systemDependencies` and one or more are missing before
the tool is compiled/installed.

Detection is always the source of truth: a prerequisite that mise can already find
on the machine (via any means — Homebrew, apt, nix, MacPorts, from source) is never
questioned. This setting only governs what happens for the *missing* subset:

- `prompt` (default) — report the missing capabilities and offer to install them
  via the first available system package manager. Falls back to `warn` when not
  running interactively.
- `auto` — install the missing packages without asking (implies the package
  manager's own non-interactive install; may use sudo per `system_packages.sudo`).
- `warn` — print the missing capabilities and copy-pasteable install commands, then
  continue with the install anyway.
- `ignore` — do nothing; skip the check entirely.

Missing *optional* dependencies never prompt or fail — they surface as a single
informational line regardless of this setting.
"""
enum = ["prompt", "auto", "warn", "ignore"]
env = "MISE_SYSTEM_DEPS"
rust_type = "SystemDepsMode"
type = "String"

[system_packages.managers]
description = "Restrict which system package managers mise will use."
docs = """
Restrict which system package managers mise will use.

By default mise acts on every manager in `[bootstrap.packages]` that is available
on the current machine. When more than one could apply (e.g. several package
managers installed on one machine, or a shared config listing managers you
don't want on this machine), set this to the subset you want:

```toml
[settings]
system_packages.managers = ["apt"]
```

This composes well with platform-specific config files
(`mise.macos.toml`, `mise.linux.toml`) for per-OS defaults.
"""
env = "MISE_SYSTEM_PACKAGES_MANAGERS"
optional = true
parse_env = "list_by_comma"
rust_type = "Vec<String>"
type = "ListString"

[system_packages.sudo]
default = true
description = "Allow `mise bootstrap packages apply` to elevate with sudo when not running as root."
docs = """
Allow `mise bootstrap packages apply` to elevate with sudo when not running as root.

When disabled, mise never runs sudo: if elevation would be required, it errors
with the exact command to run manually. mise only elevates for explicit
`mise bootstrap packages apply` invocations, logs the full command line before running
it, and skips sudo entirely when already running as root (e.g. containers/CI).
"""
env = "MISE_SYSTEM_PACKAGES_SUDO"
type = "Bool"

[task.disable_paths]
default = []
description = "Paths that mise will not look for tasks in."
docs = """
Paths that mise will not look for tasks in.

Paths are separated by the OS path separator when using the environment variable
(`:` on Unix, `;` on Windows).
"""
env = "MISE_TASK_DISABLE_PATHS"
parse_env = "list_by_os_path_separator"
